CREATE TABLE IF NOT EXISTS project_timeline (id INT, title VARCHAR(300) NOT NULL, description VARCHAR(1500) NULL, banner_image VARCHAR(300) NOT NULL, superstar BOOLEAN NOT NULL, source_url VARCHAR(255) NULL, follower_count INT NOT NULL, devlog_count INT NOT NULL, total_hours INT NOT NULL, post_count INT NOT NULL, is_hardware BOOLEAN NOT NULL, attached_mission VARCHAR(30) NULL, mission_shipped BOOLEAN NULL, request INT, CONSTRAINT pk_project_timeline PRIMARY KEY (id, request), CONSTRAINT fk_project_timeline_id__id FOREIGN KEY (id) REFERENCES projects(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_project_timeline_request__id FOREIGN KEY (request) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);